### Memory Monitoring

```javascript
export function getMemoryUsage() {
    const heap = sqlite3.wasm?.HEAPU8;
    if (!heap) return null;
    return {
        used: heap.length,
        limit: 256 * 1024 * 1024,
        percent: (heap.length / (256 * 1024 * 1024)) * 100,
    };
}

export function checkMemoryPressure() {
    const usage = getMemoryUsage();
    if (usage && usage.percent > 80) {
        console.warn(`WASM memory at ${usage.percent.toFixed(1)}%`);
        return true;
    }
    return false;
}
```

